import React, { useEffect, useRef, useState } from "react";

export default function Editor() {
  const [text, setText] = useState("");
  const [alerts, setAlerts] = useState<string[]>([]);
  const [stats, setStats] = useState({
    keystrokes: 0,
    pastes: 0
  });

  const sessionRef = useRef({
    startTime: performance.now(),
    text: "",
    keystrokes: [] as any[],
    pasteEvents: [] as any[]
  });

  const lastLengthRef = useRef(0);

  // 🔹 Add Alert
  const addAlert = (msg: string) => {
    setAlerts(prev => [msg, ...prev.slice(0, 4)]);
  };

  // 🔹 Key Tracking
  const handleKeyDown = (e: KeyboardEvent) => {
    if (["Shift", "Control", "Alt"].includes(e.key)) return;

    sessionRef.current.keystrokes.push({
      key: e.key,
      timestamp: performance.now()
    });

    setStats(prev => ({
      ...prev,
      keystrokes: prev.keystrokes + 1
    }));
  };

  // 🔹 Paste Detection
  const handlePaste = (e: ClipboardEvent) => {
    const pastedText = e.clipboardData?.getData("text") || "";

    sessionRef.current.pasteEvents.push({
      length: pastedText.length,
      timestamp: performance.now()
    });

    setStats(prev => ({
      ...prev,
      pastes: prev.pastes + 1
    }));

    addAlert(`📋 Paste detected (${pastedText.length} chars)`);
  };

  // 🔹 Text Change
  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const newText = e.target.value;
    const diff = newText.length - lastLengthRef.current;

    sessionRef.current.text = newText;
    setText(newText);

    // Spike detection
    if (diff > 20) {
      addAlert("⚠️ Sudden text spike (possible paste)");
    }

    // Mismatch detection
    if (newText.length > sessionRef.current.keystrokes.length + 10) {
      addAlert("🚨 Text without typing detected");
    }

    lastLengthRef.current = newText.length;
  };

  // 💾 Save Session
  const saveSession = () => {
    const session = {
      ...sessionRef.current,
      endTime: performance.now()
    };

    const blob = new Blob([JSON.stringify(session, null, 2)], {
      type: "application/json"
    });

    const url = URL.createObjectURL(blob);

    const a = document.createElement("a");
    a.href = url;
    a.download = "session.json";
    a.click();
  };

  // 🔹 Event Listeners
  useEffect(() => {
    window.addEventListener("keydown", handleKeyDown);
    window.addEventListener("paste", handlePaste);

    return () => {
      window.removeEventListener("keydown", handleKeyDown);
      window.removeEventListener("paste", handlePaste);
    };
  }, []);

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h2>🧠 Vi-Notes Demo</h2>

      <textarea
        value={text}
        onChange={handleChange}
        placeholder="Start typing here..."
        rows={10}
        style={{
          width: "100%",
          padding: "10px",
          fontSize: "16px",
          borderRadius: "8px"
        }}
      />

      <div style={{ marginTop: "15px" }}>
        <strong>Stats:</strong>
        <p>⌨️ Keystrokes: {stats.keystrokes}</p>
        <p>📋 Paste Events: {stats.pastes}</p>
      </div>

      <div style={{ marginTop: "15px" }}>
        <strong>Alerts:</strong>
        {alerts.length === 0 && <p>No issues detected</p>}
        {alerts.map((a, i) => (
          <p key={i} style={{ color: "red" }}>
            {a}
          </p>
        ))}
      </div>

      <button
        onClick={saveSession}
        style={{
          marginTop: "20px",
          padding: "10px",
          background: "black",
          color: "white",
          borderRadius: "6px"
        }}
      >
        💾 Save Session
      </button>
    </div>
  );
}
